public class HybridWebView extends WebView {
    private Context context;
    private WebAppInterface webAppInterface;

    public HybridWebView(Context context) {
        super(context);
        this.context = context;
        setupWebView();
    }

    public HybridWebView(Context context, AttributeSet attrs) {
        super(context, attrs);
        this.context = context;
        setupWebView();
    }

    private void setupWebView() {
        WebSettings webSettings = getSettings();
        webSettings.setJavaScriptEnabled(true);
        webSettings.setDomStorageEnabled(true);
        webSettings.setDatabaseEnabled(true);
        webSettings.setCacheMode(WebSettings.LOAD_DEFAULT);
        webSettings.setAppCacheEnabled(true);
        webSettings.setAllowFileAccess(true);
        webSettings.setAllowContentAccess(true);
        webSettings.setAllowFileAccessFromFileURLs(true);
        webSettings.setAllowUniversalAccessFromFileURLs(true);
        webSettings.setMixedContentMode(WebSettings.MIXED_CONTENT_ALWAYS_ALLOW);

        setWebViewClient(new WebViewClient() {
            @Override
            public boolean shouldOverrideUrlLoading(WebView view, String url) {
                return false;
            }

            @Override
            public void onPageFinished(WebView view, String url) {
                super.onPageFinished(view, url);
            }
        });

        setWebChromeClient(new WebChromeClient() {
            @Override
            public void onProgressChanged(WebView view, int newProgress) {
                super.onProgressChanged(view, newProgress);
            }
        });

        webAppInterface = new WebAppInterface(context);
        addJavascriptInterface(webAppInterface, "Android");
    }

    public void loadWebsite(String url) {
        loadUrl(url);
    }

    public class WebAppInterface {
        Context mContext;

        WebAppInterface(Context c) {
            mContext = c;
        }

        @JavascriptInterface
        public void openCamera() {
            Intent intent = new Intent(MediaStore.ACTION_IMAGE_CAPTURE);
            if (intent.resolveActivity(mContext.getPackageManager()) != null) {
                ((Activity) mContext).startActivityForResult(intent, 1);
            }
        }

        @JavascriptInterface
        public void getLocation() {
            LocationManager locationManager = (LocationManager) mContext.getSystemService(Context.LOCATION_SERVICE);
            if (ActivityCompat.checkSelfPermission(mContext, Manifest.permission.ACCESS_FINE_LOCATION) == PackageManager.PERMISSION_GRANTED) {
                Location location = locationManager.getLastKnownLocation(LocationManager.GPS_PROVIDER);
                if (location != null) {
                    String locationData = location.getLatitude() + "," + location.getLongitude();
                    ((Activity) mContext).runOnUiThread(() -> {
                        loadUrl("javascript:receiveLocation('" + locationData + "')");
                    });
                }
            }
        }

        @JavascriptInterface
        public void makePayment(String amount) {
            // Implement payment logic
            Intent intent = new Intent(mContext, PaymentActivity.class);
            intent.putExtra("amount", amount);
            mContext.startActivity(intent);
        }

        @JavascriptInterface
        public void showToast(String message) {
            Toast.makeText(mContext, message, Toast.LENGTH_SHORT).show();
        }
    }
}